class KernelCa6k00282Custom {
public:
    __aicore__ inline KernelCa6k00282Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t N, uint32_t C,
                                uint32_t spatialSize, uint32_t tileLen,
                                float eps)
    {
        N_ = N;
        C_ = C;
        spatialSize_ = spatialSize;
        tileLen_ = tileLen;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, N_ * C_ * spatialSize_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, N_ * C_ * spatialSize_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));      // for chunks (reusable)
        pipe_.InitBuffer(scalarQueue_, BUFFER_NUM, sizeof(float));     // for reduction results
    }

    __aicore__ inline void Process()
    {
        if (spatialSize_ == 0 || tileLen_ == 0) return;

        uint32_t blockIdx = AscendC::GetBlockIdx();
        if (blockIdx >= N_ * C_) return;

        uint32_t n = blockIdx / C_;
        uint32_t c = blockIdx % C_;
        uint32_t baseOffset = n * C_ * spatialSize_ + c * spatialSize_;

        // ----- First pass: compute sum and sumSq over all spatial elements -----
        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t remaining = spatialSize_;
        uint32_t offset = 0;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;

            // Load tile from global
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseOffset + offset], curLen);

            // Reduce sum in chunks (REDUCE_CHUNK)
            uint32_t pos = 0;
            while (pos < curLen) {
                uint32_t chunk = (curLen - pos > REDUCE_CHUNK) ? REDUCE_CHUNK : (curLen - pos);

                // Sum chunk
                AscendC::LocalTensor<float> sumChunk = scalarQueue_.AllocTensor<float>();
                AscendC::ReduceAdd(sumChunk, xLocal[pos], chunk);
                sum += sumChunk(0);
                scalarQueue_.FreeTensor(sumChunk);

                // Square chunk and reduce to sumSq
                AscendC::LocalTensor<float> sqChunk = tmpQueue_.AllocTensor<float>();
                AscendC::Mul(sqChunk, xLocal[pos], xLocal[pos], chunk);
                AscendC::LocalTensor<float> sumSqChunk = scalarQueue_.AllocTensor<float>();
                AscendC::ReduceAdd(sumSqChunk, sqChunk, chunk);
                sumSq += sumSqChunk(0);
                scalarQueue_.FreeTensor(sumSqChunk);

                tmpQueue_.FreeTensor(sqChunk);
                pos += chunk;
            }

            inQueueX_.FreeTensor(xLocal);
            offset += curLen;
            remaining -= curLen;
